1	/**
2	 * Agent Triage
3	 *
4	 * Triggered by `platform/event.stored`. Loads the org's `.lightfast/` config
5	 * (SPEC.md + skill manifests) from the indexed GitHub repo, runs one Claude
6	 * Haiku 4.5 structured-output call to decide whether any skill should run,
7	 * and emits `platform/agent.decided` for both skip/invoke outcomes.
8	 *
9	 * v1 is read-only — no memory writes, no skill execution, no tool calls.
10	 */
11	
12	import { gateway } from "@ai-sdk/gateway";
13	import { db } from "@db/app/client";
