36	
37	export const platformAgentTriage = inngest.createFunction(
38	  {
39	    id: "platform/agent.triage",
40	    name: "Agent Triage",
41	    description:
42	      "Loads .lightfast config and runs a triage LLM call on stored events",
43	    retries: 2,
