85	   * Source: POST /connections/:id/proxy/execute
86	   *
87	   * Handles: endpoint validation, auth injection, 401 retry.
88	   * Returns: raw { status, data, headers }.
89	   */
90	  execute: serviceProcedure
91	    .input(
92	      z.object({
93	        installationId: z.string(),
94	        endpointId: z.string().min(1),
95	        pathParams: z.record(z.string(), z.string()).optional(),
96	        queryParams: z.record(z.string(), z.string()).optional(),
97	        body: z.unknown().optional(),
98	      })
99	    )
100	    .mutation(async ({ input }) => {
101	      const installation = await db.query.gatewayInstallations.findFirst({
102	        where: eq(gatewayInstallations.id, input.installationId),
103	      });
104	
105	      if (!installation) {
106	        throw new TRPCError({
107	          code: "NOT_FOUND",
108	          message: "Connection not found",
109	        });
110	      }
111	
112	      if (installation.status !== "active") {
113	        throw new TRPCError({
114	          code: "BAD_REQUEST",
115	          message: `Installation not active (status: ${installation.status})`,
116	        });
117	      }
118	
119	      const providerName = installation.provider;
120	      const providerDef = getProvider(providerName);
121	      if (!providerDef) {
122	        throw new TRPCError({
123	          code: "BAD_REQUEST",
124	          message: "Unknown provider",
125	        });
126	      }
127	
128	      const config = providerConfigs[providerName];
129	
130	      // Widen to base ProviderApi for runtime-dynamic endpoint/header access.
131	      // Each provider's TApi satisfies ProviderApi -- structural widening, not a cast.
132	      const api: ProviderApi = providerDef.api;
133	
134	      // Validate endpoint exists in catalog
135	      const endpoint = api.endpoints[input.endpointId];
136	      if (!endpoint) {
137	        throw new TRPCError({
138	          code: "BAD_REQUEST",
139	          message: `Unknown endpoint: ${input.endpointId}. Available: ${Object.keys(api.endpoints).join(", ")}`,
140	        });
141	      }
142	
143	      // Get active token.
144	      // If the endpoint declares its own buildAuth, use it (e.g. GitHub App JWT for
145	      // app-level endpoints). Otherwise fall through to the default per-installation token flow.
146	      let token: string;
147	      try {
148	        if (endpoint.buildAuth) {
149	          token = await endpoint.buildAuth(config);
150	        } else {
151	          // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
152	          // but the helper takes the base ProviderDefinition. The generic parameters are
153	          // erased at runtime -- the cast is safe because the concrete type is a supertype.
154	          ({ token } = await getActiveTokenForInstallation(
155	            installation,
156	            config,
157	            providerDef as ProviderDefinition
158	          ));
159	        }
160	      } catch (err) {
161	        const message = parseError(err);
162	        log.error("[proxy] token acquisition failed", {
163	          installationId: input.installationId,
164	          provider: providerName,
165	          error: message,
166	        });
167	        throw new TRPCError({
168	          code: "INTERNAL_SERVER_ERROR",
169	          message: `token_error: ${message}`,
170	        });
171	      }
172	
173	      // Build URL
174	      let path = endpoint.path;
175	      if (input.pathParams) {
176	        for (const [key, val] of Object.entries(input.pathParams)) {
177	          path = path.replace(`{${key}}`, encodeURIComponent(val));
178	        }
179	      }
180	
181	      let url = `${api.baseUrl}${path}`;
182	      if (input.queryParams && Object.keys(input.queryParams).length > 0) {
183	        url += `?${new URLSearchParams(input.queryParams).toString()}`;
184	      }
185	
186	      // Build headers
187	      const authHeader = api.buildAuthHeader
188	        ? api.buildAuthHeader(token)
189	        : `Bearer ${token}`;
190	
191	      const headers: Record<string, string> = {
192	        Authorization: authHeader,
193	        ...(api.defaultHeaders ?? {}),
194	      };
195	
196	      // Build fetch options
197	      const fetchOptions: RequestInit = {
198	        method: endpoint.method,
199	        headers,
200	        signal: AbortSignal.timeout(endpoint.timeout ?? 30_000),
201	      };
202	
203	      if (input.body) {
204	        fetchOptions.body = JSON.stringify(input.body);
205	        headers["Content-Type"] = "application/json";
206	      }
207	
208	      // Execute with 401 retry
209	      let response = await fetch(url, fetchOptions);
210	
211	      if (response.status === 401) {
212	        let freshToken: string | null = null;
213	        if (endpoint.buildAuth) {
214	          try {
215	            freshToken = await endpoint.buildAuth(config);
216	          } catch (retryErr) {
217	            log.warn("[proxy] auth rebuild failed during 401 retry", {
218	              installationId: input.installationId,
219	              provider: providerName,
220	              endpointId: input.endpointId,
221	              error: parseError(retryErr),
222	            });
223	            // fall through without retry
224	          }
225	        } else {
226	          // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
227	          // but the helper takes the base ProviderDefinition. The generic parameters are
228	          // erased at runtime -- the cast is safe because the concrete type is a supertype.
229	          freshToken = await forceRefreshToken(
230	            installation,
231	            config,
232	            providerDef as ProviderDefinition
233	          );
234	        }
235	        if (freshToken && freshToken !== token) {
236	          headers.Authorization = api.buildAuthHeader
237	            ? api.buildAuthHeader(freshToken)
238	            : `Bearer ${freshToken}`;
239	          response = await fetch(url, { ...fetchOptions, headers });
240	        }
241	      }
242	
243	      // Return raw response -- no parsing, no transformation
244	      const data = await response.json().catch((parseErr: unknown) => {
245	        log.warn("[proxy] response body parse failed", {
246	          installationId: input.installationId,
247	          provider: providerName,
248	          endpointId: input.endpointId,
249	          status: response.status,
250	          error: parseError(parseErr),
251	        });
252	        return null;
253	      });
254	      const responseHeaders: Record<string, string> = {};
255	      response.headers.forEach((value, key) => {
256	        responseHeaders[key] = value;
257	      });
258	
259	      return {
260	        status: response.status,
261	        data,
262	        headers: responseHeaders,
263	      };
264	    }),

